class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    Adaptive Threshold Cooperation strategy for N-Player Public Goods Game.
    
    Defects in round 0 to probe opponent behavior. In intermediate rounds 1 to r-2,
    cooperates if the observed opponent cooperation rate meets or exceeds the
    threshold 1/k, otherwise defects. Defects in the final round r-1 to exploit
    the one-shot dominant strategy with no future reputation consequences.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        k = self.game_description.k
        round_num = history.round_number
        if round_num == 0:
            return Action.D
        if round_num == r - 1:
            return Action.D
        m = history.opponent_cooperators[-1]
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        p = m / n_opponents
        threshold = 1.0 / k
        if p >= threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_89(BaseStrategy):
    """
    Adaptive Conditional Cooperation with Endgame Defection.
    
    Cooperates initially to test the environment, adaptively cooperates or defects
    in middle rounds based on observed cooperation rates and a threshold,
    and unconditionally defects in the final two rounds via backward induction.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.threshold = math.ceil(self.n * self.k / (self.k + self.n))

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        if current_round >= self.r - 2:
            return Action.D
        prev_round_opponent_cooperators = history.opponent_cooperators[current_round - 1]
        prev_round_total_cooperators = prev_round_opponent_cooperators + (1 if history.my_actions[current_round - 1] else 0)
        m = prev_round_total_cooperators
        total_observed_cooperators = np.sum(history.opponent_cooperators[:current_round]) + np.sum(history.my_actions[:current_round])
        total_actions = self.n * current_round
        avg_coop = total_observed_cooperators / total_actions if total_actions > 0 else 0.0
        if m >= self.threshold:
            return Action.C
        elif avg_coop < self.n / 2:
            return Action.D
        else:
            remaining_rounds = self.r - 2 - current_round
            total_middle_rounds = max(1, self.r - 3)
            probability = remaining_rounds / total_middle_rounds
            if random.random() < probability:
                return Action.C
            else:
                return Action.D

class Strategy_SELFINTERESTED_90(BaseStrategy):
    """
    Conditional Defection with Information Gathering strategy.
    
    Cooperates in the first round to gather baseline information about opponent 
    strategies. In all subsequent rounds (middle and final), defects because:
    1. Defection is the strictly dominant action in any single round (1 - k/n > 0)
    2. By round 2, opponent tendencies are revealed; cooperation provides no future benefit
    3. Final rounds have zero continuation value, making defection optimal
    
    Expected total payoff: approximately r (defection in nearly all rounds).
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    Adaptive Threshold Strategy with Last-Round Defection for N-Player Public Goods Game.
    
    Cooperates in round 1 to gather information, maintains cooperation if aggregate
    cooperation meets threshold τ = ⌈n/k⌉ in middle rounds, and always defects in
    the final round due to backward induction.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.threshold = math.ceil(game_description.n_players / game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        previous_opponent_cooperators = history.opponent_cooperators[-1]
        previous_own_action = 1 if history.my_actions[-1] else 0
        total_cooperators_previous = previous_opponent_cooperators + previous_own_action
        if total_cooperators_previous >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Threshold-Based Reciprocal Defection Strategy for N-Player Public Goods Game.
    
    Round 1: Defect as a safe probe to reveal opponent composition.
    
    Rounds 2+: Cooperate if the number of cooperators observed in the 
    immediately preceding round meets or exceeds the threshold ⌈n/k⌉, 
    otherwise defect. This implements reciprocal cooperation based on 
    whether the public good's return exceeds the private endowment value.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.threshold = math.ceil(game_description.n_players / game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        cooperators_last_round = history.opponent_cooperators[-1]
        if cooperators_last_round >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Adaptive Exploitation Strategy for N-Player Public Goods Game.
    
    Defects in round 1 and final round. In intermediate rounds, cooperates only if
    the expected payoff from the public good (based on empirical average cooperation
    rate) exceeds the threshold of 0.5, which is conservative relative to the
    guaranteed payoff of 1 from defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == self.game_description.n_rounds - 1:
            return Action.D
        total_cooperators = 0
        for t in range(current_round):
            total_cooperators += int(history.my_actions[t]) + history.opponent_cooperators[t]
        avg_cooperation_rate = total_cooperators / (current_round * self.game_description.n_players)
        expected_payoff = self.game_description.k / self.game_description.n_players * avg_cooperation_rate
        if expected_payoff > 0.5:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    Conditional Cooperation with Exploitation.
    
    First round: Cooperate to establish baseline.
    Middle rounds: Cooperate if observed cooperation rate exceeds threshold (k-1)/k.
    Final round: Exploit if cooperation was above threshold, otherwise match behavior.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.cooperation_threshold = (game_description.k - 1) / game_description.k
        self.cooperation_rates = []

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        if current_round == 0:
            return Action.C
        prev_opponent_cooperators = history.opponent_cooperators[-1]
        prev_self_cooperated = history.my_actions[-1]
        total_cooperators_prev = prev_opponent_cooperators + (1 if prev_self_cooperated else 0)
        coop_rate = total_cooperators_prev / n
        self.cooperation_rates.append(coop_rate)
        is_final_round = current_round == r - 1
        if is_final_round:
            if coop_rate > self.cooperation_threshold:
                return Action.D
            elif coop_rate > 0.5:
                return Action.C
            else:
                return Action.D
        elif coop_rate > self.cooperation_threshold:
            return Action.C
        else:
            return Action.D

