        n_rounds = self.game_description.n_rounds
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        if k / n < 0.6:
            return Action.D
        cooperation_threshold = (n - 1) * 0.75
        previous_opponent_cooperators = history.opponent_cooperators[-1]
        if previous_opponent_cooperators >= cooperation_threshold:
            return Action.C
        return Action.D

