class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Adaptive Conditional Cooperation Strategy for N-Player Public Goods Game.
    
    Cooperates when previous round cooperation meets threshold (n*k)/(k+1),
    defects unconditionally in final round, and uses threshold-based decision in round 1.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.threshold = game_description.n_players * game_description.k / (game_description.k + 1)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        if current_round == n_rounds - 1:
            return Action.D
        if current_round == 0:
            if self.threshold < 1:
                return Action.C
            else:
                return Action.D
        c_prev = history.opponent_cooperators[-1]
        if c_prev >= self.threshold:
            return Action.C
        else:
            return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Adaptive Defection with Conditional Cooperation.
    Defects by default, cooperates only when empirical evidence suggests
    sufficient cooperation to generate substantial public good benefits.
    
    - Round 0: Defect to establish baseline
    - Rounds 1 to r-2: Cooperate if observed cooperators >= threshold, with probabilistic tie-breaking
    - Final round: Defect unconditionally
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.threshold = math.ceil(game_description.n_players / game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        k = self.game_description.k
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            return Action.D
        opponent_cooperators_prev = history.opponent_cooperators[-1]
        my_action_prev = history.my_actions[-1]
        total_cooperators_prev = opponent_cooperators_prev + (1 if my_action_prev else 0)
        if total_cooperators_prev > self.threshold:
            return Action.C
        elif total_cooperators_prev == self.threshold:
            return Action.C if random.random() < k / self.game_description.n_players else Action.D
        else:
            return Action.D

